window.registerHardware = async () => {
    const status = document.getElementById('status');
    const btn = document.getElementById('reg-btn');
    btn.disabled = true;
    status.innerText = "EXTRACTING_SILICON_DNA...";

    if (!navigator.gpu) return;
    const adapter = await navigator.gpu.requestAdapter();
    const info = adapter.requestAdapterInfo ? await adapter.requestAdapterInfo() : {};

    const specs = {
        vendor: info.vendor || "Unknown",
        architecture: info.architecture || "Unknown",
        device: info.device || "Unknown",
        features: Array.from(adapter.features.keys ? adapter.features.keys() : adapter.features.values()),
        limits: {}
    };

    // Extract all numerical limits
    for (const key in adapter.limits) {
        specs.limits[key] = adapter.limits[key];
    }

    status.innerText = "POSTING_TO_RELAY...";

    try {
        const sid = new URLSearchParams(window.location.search).get('session') || 'LOCAL';
        await fetch(`/relay/${sid}/hardware_specs`, {
            method: 'POST',
            body: JSON.stringify(specs)
        });
        status.innerText = "SYNC_COMPLETE. AGENT_NOW_HARDWARE_AWARE.";
        status.style.color = "#00ff9d";
        window.axiomaticLog({ event: 'Hardware_Registered', specs });
    } catch(e) {
        status.innerText = "SYNC_FAILED: " + e.message;
    }
}
